<section class="eco-card"><h1>Health checks</h1><?php if (!empty($statusMessage)): ?><div class="eco-alert"><?= e((string)$statusMessage) ?></div><?php endif; ?><?php if (!empty($errorMessage)): ?><div class="eco-alert"><?= e((string)$errorMessage) ?></div><?php endif; ?><table class="eco-table"><thead><tr><th>ID</th><th>Code</th><th>Name</th><th>Type</th><th>Target</th><th>Interval</th><th>Timeout</th><th>Status</th><th>Último resultado</th><th>Última ejecución</th><th>Acción</th></tr></thead><tbody><?php foreach (($healthChecks ?? []) as $row): ?><tr><td><?= e((string)$row['id']) ?></td><td><?= e((string)$row['code']) ?></td><td><?= e((string)$row['name']) ?></td><td><span class="eco-badge"><?= e((string)$row['check_type']) ?></span></td><td><?= e((string)($row['target'] ?? '')) ?></td><td><?= e((string)$row['interval_seconds']) ?></td><td><?= e((string)$row['timeout_seconds']) ?></td><td><span class="eco-badge"><?= e((string)$row['status']) ?></span></td><td><?= e((string)($row['last_result_status'] ?? '-')) ?></td><td><?= e((string)($row['last_checked_at'] ?? '-')) ?></td><td><form method="post" action="/system/health/<?= e((string)$row['id']) ?>/run"><input type="hidden" name="_csrf" value="<?= e((string)$csrfToken) ?>"><button class="eco-button btn" type="submit">Run</button></form></td></tr><?php endforeach; ?></tbody></table></section>
